MERGE INTO CONSULTAS FIN USING (SELECT '002425BALANCECONCILIACIONFISCAL' INFORME ,TO_CLOB(q'[SELECT COMPANIA, ANO, CODIGO, NATURALEZA, CLASE, NVL(SALDO,0) SALDO, NVL(SALDO1, 0) SALDO1, 
                 NOMBRE, NVL(DEBITO, 0) DEBITO, NVL(CREDITO, 0) CREDITO, NVL(SALDOANTDEBITO, 0) SALDOANTDEBITO, NVL(SALDOANTCREDITO, 0) SALDOANTCREDITO, 
                 NVL(SALDONUEDEBITO, 0) SALDONUEDEBITO, NVL(SALDONUECREDITO, 0) SALDONUECREDITO, NVL(SALDONUEDEBITONODEDUCIBLE, 0) SALDONUEDEBITONODEDUCIBLE, 
                 NVL(SALDONUECREDITONODEDUCIBLE, 0) SALDONUECREDITONODEDUCIBLE, NVL(SALDODEBITOFISCAL, 0) SALDODEBITOFISCAL, NVL(SALDOCREDITOFISCAL, 0) SALDOCREDITOFISCAL, 
                 NVL(SALDOFISCAL, 0) SALDOFISCAL, NVL(DEDUCIBLE, 0) DEDUCIBLE, 
                 TERCERO, AUXILIAR, REFERENCIA_CONTABLE, CENTRO_COSTO 
          FROM TMPBALANCEDEDUCIBLE 
          WHERE LENGTH(CODIGO) <= s$digitos$s 
          s$checkceorcondicion$s
          s$condicioncuentas$s
          ORDER BY ID]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);